        const splitMetaMap = isBodybuildingPro ? bodybuildingSplitCardMeta : isFatLossPro ? fatLossSplitCardMeta : generalFitnessSplitCardMeta;
        const splitEyebrow = isBodybuildingPro ? 'Bodybuilding Split' : isSportPerformancePro ? 'Sport Performance Split' : isFatLossPro ? 'Fat Loss Split' : 'General Fitness Split';
        const splitSubtitle = isBodybuildingPro
